INSERT INTO inventory (sku, name, description, long_description, quantity_available, quantity_reserved, unit_price_cents, cost_cents, weight_grams, category, tags, attributes, is_active) VALUES
  ('WDG-001', 'Standard Widget', 'A reliable everyday widget', 'The Standard Widget is our best-selling product, trusted by over 10,000 customers worldwide. Built with precision-machined aluminum components and featuring our patented QuickLock mechanism, it delivers consistent performance in any environment. Rated for continuous operation up to 85°C with a mean time between failures of 50,000 hours.', 500, 12, 999, 450, 150, 'widgets', ARRAY['popular', 'sale', 'bestseller'], '{"color": ["blue", "red", "silver"], "material": "aluminum", "warranty_months": 24, "certifications": ["CE", "UL", "FCC"]}', true),
  ('WDG-002', 'Premium Widget', 'Our finest widget with enhanced features', 'The Premium Widget represents the pinnacle of widget engineering. Crafted from aerospace-grade titanium with hand-polished surfaces, each unit undergoes 47 quality checkpoints before shipping. Features include adaptive resonance dampening, integrated diagnostics via Bluetooth 5.3, and our exclusive LifeGuard protection system.', 200, 5, 2499, 1100, 200, 'widgets', ARRAY['premium', 'featured'], '{"color": ["titanium", "matte-black", "rose-gold"], "material": "titanium", "warranty_months": 36, "certifications": ["CE", "UL", "FCC", "ISO9001"]}', true),
  ('WDG-003', 'Mini Widget', 'Compact and portable', 'The Mini Widget packs full-size performance into a pocket-friendly form factor. At just 80 grams, it is the lightest widget in its class while maintaining 92% of the output capacity of our Standard model. Perfect for field work, travel, or anywhere space is at a premium.', 1000, 30, 499, 200, 80, 'widgets', ARRAY['popular', 'compact', 'travel'], '{"color": ["white", "black"], "material": "polycarbonate", "warranty_months": 12}', true),
  ('WDG-004', 'Widget Pro X', 'Professional-grade widget with digital display', 'The Widget Pro X bridges the gap between our consumer and industrial lines. Its integrated OLED display provides real-time feedback on 12 operating parameters, while the ruggedized housing withstands drops from up to 2 meters onto concrete. USB-C charging delivers 0-100% in 45 minutes.', 150, 3, 3999, 1800, 280, 'widgets', ARRAY['premium', 'pro', 'new'], '{"color": ["gunmetal", "orange"], "material": "carbon-fiber-reinforced-nylon", "warranty_months": 36, "display": "OLED 1.3in", "battery_mah": 2400}', true),
  ('WDG-005', 'Widget Lite', 'Budget-friendly basic widget', 'An affordable entry point to the Widget ecosystem. The Widget Lite uses simplified internals that still deliver reliable performance for everyday tasks. Ships in 100% recyclable packaging.', 2000, 0, 299, 120, 100, 'widgets', ARRAY['budget', 'eco'], '{"color": ["green", "blue"], "material": "recycled-plastic", "warranty_months": 6}', true),
  ('WDG-006', 'Widget Industrial', 'Heavy-duty widget for harsh environments', 'Rated IP68 and MIL-STD-810H compliant. The Industrial Widget operates reliably from -40°C to +125°C and withstands sustained vibration, shock, and humidity that would destroy consumer models. Used by oil rigs, mining operations, and military installations worldwide.', 75, 2, 7999, 3500, 450, 'widgets', ARRAY['industrial', 'rugged', 'mil-spec'], '{"color": ["safety-yellow", "olive-drab"], "material": "hardened-steel", "warranty_months": 60, "ip_rating": "IP68", "temp_range_c": "-40 to 125"}', true),
  ('GDG-001', 'Basic Gadget', 'Entry-level gadget', 'The Basic Gadget is your gateway to the Gadget world. Simple one-button operation, automatic calibration, and universal compatibility make it ideal for first-time users. Includes a quick-start guide in 14 languages.', 300, 8, 1999, 900, 300, 'gadgets', ARRAY['new', 'beginner'], '{"color": ["white", "gray"], "material": "ABS-plastic", "warranty_months": 12, "connectivity": "USB-C"}', true),
  ('GDG-002', 'Pro Gadget', 'Professional-grade gadget', 'The Pro Gadget is the tool of choice for demanding professionals. Dual-core processing delivers 3x the throughput of the Basic model, while 64GB of onboard storage logs up to 2 million data points. Programmable via our open-source SDK with Python and Node.js bindings.', 150, 10, 4999, 2200, 450, 'gadgets', ARRAY['premium', 'pro', 'featured'], '{"color": ["matte-black", "arctic-white"], "material": "carbon-fiber", "warranty_months": 24, "connectivity": ["USB-C", "BLE5.3", "WiFi6"], "storage_gb": 64}', true),
  ('GDG-003', 'Mega Gadget', 'Our largest and most powerful gadget', 'The Mega Gadget is an engineering marvel. Quad-core processing, 256GB storage, a 7-inch high-brightness display, and an integrated thermal management system allow it to handle workloads that would require three competing products. Hot-swappable modules let you customize its capabilities in the field.', 50, 4, 9999, 4500, 800, 'gadgets', ARRAY['premium', 'limited', 'flagship'], '{"color": ["titanium"], "material": "titanium-alloy", "warranty_months": 36, "connectivity": ["USB-C", "BLE5.3", "WiFi6", "Ethernet"], "storage_gb": 256, "display": "7in IPS 1000nit"}', true),
  ('GDG-004', 'Gadget Nano', 'Ultra-compact gadget', 'The smallest gadget ever made. At 25 grams, the Nano clips to a keychain or lanyard and delivers surprisingly capable performance for quick measurements and spot checks.', 400, 0, 1499, 650, 25, 'gadgets', ARRAY['compact', 'new', 'portable'], '{"color": ["black", "red", "blue", "green"], "material": "anodized-aluminum", "warranty_months": 12, "battery_mah": 800}', true),
  ('GDG-005', 'Gadget Studio', 'Creative professional gadget with touchscreen', 'Built for creators. The Studio features a pressure-sensitive 10-inch touchscreen, stylus support, and integrations with Adobe Creative Suite, Figma, and Blender. 512GB NVMe storage handles even the largest project files.', 80, 6, 14999, 7000, 650, 'gadgets', ARRAY['premium', 'creative', 'new'], '{"color": ["space-gray"], "material": "magnesium-alloy", "warranty_months": 24, "display": "10in OLED", "storage_gb": 512, "stylus_included": true}', true),
  ('ACC-001', 'Widget Adapter', 'Connect widgets to gadgets', 'The universal adapter that bridges the Widget and Gadget ecosystems. Supports all current and legacy connector types with automatic protocol negotiation.', 800, 20, 799, 300, 50, 'accessories', ARRAY['popular', 'essential'], '{"compatibility": ["WDG-*", "GDG-*"], "connector": "universal"}', true),
  ('ACC-002', 'Gadget Case', 'Protective carrying case', 'Hard-shell EVA case with custom-molded interior, accessory mesh pocket, and carabiner clip. Splash-proof zipper rated IPX4.', 400, 5, 1499, 600, 180, 'accessories', ARRAY['new', 'protection'], '{"fits": ["GDG-001", "GDG-002", "GDG-004"], "material": "EVA-foam", "waterproof": "IPX4"}', true),
  ('ACC-003', 'Power Supply', 'Universal power supply unit', '65W GaN charger with USB-C PD 3.1 and USB-A QC4+ ports. Folds flat for travel. Works with 100-240V input worldwide.', 600, 15, 2999, 1200, 120, 'accessories', ARRAY['essential', 'travel'], '{"wattage": 65, "ports": ["USB-C PD", "USB-A QC4+"], "input_voltage": "100-240V", "certifications": ["UL", "CE", "FCC"]}', true),
  ('ACC-004', 'Calibration Kit', 'Precision calibration tools', 'NIST-traceable calibration standards and fixtures for Pro and Mega Gadget models. Includes reference samples, alignment jig, and calibration certificate valid for 12 months.', 100, 2, 3999, 1800, 350, 'accessories', ARRAY['pro', 'precision'], '{"compatible_with": ["GDG-002", "GDG-003", "GDG-005"], "certification": "NIST-traceable", "validity_months": 12}', true),
  ('ACC-005', 'Widget Stand', 'Desktop display and charging stand', 'Elegant aluminum stand that displays your widget at the perfect viewing angle while keeping it charged via integrated wireless charging pad.', 300, 0, 1999, 800, 250, 'accessories', ARRAY['new', 'desktop'], '{"material": "aluminum", "charging": "Qi 15W", "compatible_with": ["WDG-001", "WDG-002", "WDG-004"]}', true),
  ('ACC-006', 'Premium Cable Set', 'Braided cables in 3 lengths', 'Set of three braided nylon USB-C cables (0.3m, 1m, 2m) with reinforced strain reliefs rated for 25,000+ bend cycles.', 500, 8, 1299, 400, 90, 'accessories', ARRAY['popular', 'cables'], '{"lengths_m": [0.3, 1, 2], "material": "braided-nylon", "data_rate": "USB3.2 Gen2"}', true),
  ('ACC-007', 'Travel Pouch', 'Compact organizer for accessories', 'Water-resistant nylon pouch with elastic loops and zippered mesh compartments. Fits cables, adapters, and small gadgets.', 350, 0, 899, 300, 60, 'accessories', ARRAY['travel', 'organizer'], '{"material": "ballistic-nylon", "waterproof": "IPX3", "compartments": 5}', true),
  ('ACC-008', 'Screen Protector Pack', 'Tempered glass screen protectors (3-pack)', 'Ultra-thin 0.33mm tempered glass with oleophobic coating and bubble-free adhesive. Compatible with Gadget Studio and Mega Gadget displays.', 600, 0, 699, 150, 30, 'accessories', ARRAY['protection', 'display'], '{"thickness_mm": 0.33, "hardness": "9H", "quantity": 3, "compatible_with": ["GDG-003", "GDG-005"]}', true),
  ('BDL-001', 'Widget Starter Bundle', 'Standard Widget + Adapter + Case', 'Everything you need to get started. Save 15% versus buying individually.', 200, 3, 2799, 1200, 380, 'bundles', ARRAY['bundle', 'value', 'popular'], '{"includes": ["WDG-001", "ACC-001", "ACC-002"], "discount_pct": 15}', true),
  ('BDL-002', 'Pro Bundle', 'Pro Gadget + Calibration Kit + Power Supply + Case', 'The complete professional setup at a 20% discount.', 50, 1, 9999, 4200, 1100, 'bundles', ARRAY['bundle', 'pro', 'value'], '{"includes": ["GDG-002", "ACC-004", "ACC-003", "ACC-002"], "discount_pct": 20}', true),
  ('BDL-003', 'Ultimate Bundle', 'Mega Gadget + Studio + Calibration Kit + Cable Set + Power Supply', 'Our most comprehensive package for the serious professional. Includes everything you need plus a premium carrying case.', 25, 2, 27999, 13000, 2000, 'bundles', ARRAY['bundle', 'premium', 'limited'], '{"includes": ["GDG-003", "GDG-005", "ACC-004", "ACC-006", "ACC-003"], "discount_pct": 25}', true),
  ('WDG-007', 'Widget Vintage', 'Retro-styled widget', 'A modern widget wrapped in a gorgeous walnut and brass housing. Hand-finished by our craftspeople, each unit is unique.', 30, 0, 5999, 2800, 320, 'widgets', ARRAY['limited', 'vintage', 'gift'], '{"color": ["walnut-brass"], "material": "walnut-wood-brass", "warranty_months": 24, "handmade": true}', true),
  ('GDG-006', 'Gadget Outdoor', 'Rugged outdoor gadget', 'Built for adventure. IP67 rated, shock-resistant, with an integrated GPS receiver and solar charging panel. 72-hour battery life in the field.', 120, 5, 6999, 3200, 380, 'gadgets', ARRAY['outdoor', 'rugged', 'adventure'], '{"ip_rating": "IP67", "battery_hours": 72, "solar_charging": true, "gps": true, "material": "fiber-reinforced-polymer"}', true),
  ('ACC-009', 'Wireless Charging Pad', 'Qi2 compatible fast wireless charger', 'Supports Qi2 magnetic alignment for perfect placement every time. Up to 15W fast charging.', 250, 3, 2499, 900, 95, 'accessories', ARRAY['charging', 'wireless', 'new'], '{"standard": "Qi2", "wattage": 15, "magnetic": true}', true),
  ('ACC-010', 'Mounting Bracket', 'Universal mounting solution', 'VESA-compatible mounting bracket with adjustable tilt and swivel. Supports wall, desk-clamp, and pole mounting configurations.', 180, 0, 1799, 700, 400, 'accessories', ARRAY['mounting', 'desktop', 'industrial'], '{"vesa_pattern": "75x75/100x100", "max_weight_kg": 5, "tilt_degrees": 45, "swivel_degrees": 360}', true),
  ('WDG-008', 'Widget Micro', 'Smallest widget in the lineup', 'The Widget Micro is barely larger than a coin but delivers impressive output for its size. Uses our proprietary micro-machining process for components just 0.3mm thick.', 750, 0, 399, 180, 15, 'widgets', ARRAY['compact', 'micro', 'new'], '{"weight_g": 15, "diameter_mm": 22, "thickness_mm": 8, "material": "stainless-steel"}', true),
  ('GDG-007', 'Gadget Edu', 'Educational gadget for STEM learning', 'Designed for classrooms and makerspaces. Includes curriculum-aligned lesson plans for grades 6-12, with sensors for temperature, light, sound, motion, and humidity. Blockly and Python programming support.', 500, 50, 2999, 1300, 220, 'gadgets', ARRAY['education', 'stem', 'classroom'], '{"sensors": ["temperature", "light", "sound", "motion", "humidity"], "programming": ["Blockly", "Python"], "grade_level": "6-12", "qty_per_classroom_kit": 10}', true),
  ('ACC-011', 'Anti-Static Mat', 'ESD-safe work surface', 'Conductive rubber mat with snap-on ground cord. Essential for handling sensitive electronic components.', 200, 0, 2299, 900, 800, 'accessories', ARRAY['esd', 'workspace', 'pro'], '{"size_cm": "60x120", "material": "conductive-rubber", "surface_resistance_ohm": "1e6-1e9"}', true),
  ('ACC-012', 'Lens Kit', 'Interchangeable lens set for Gadget Studio', 'Four precision-ground glass lenses (macro, wide, telephoto, fisheye) in a padded carrying case. Magnetic snap-on mounting.', 60, 4, 4999, 2200, 280, 'accessories', ARRAY['creative', 'pro', 'lenses'], '{"lenses": ["macro 10x", "wide 0.6x", "telephoto 2x", "fisheye 180deg"], "mount_type": "magnetic", "compatible_with": ["GDG-005"]}', true);
