INSERT INTO reviews (user_id, sku, rating, title, body, verified_purchase, helpful_count) VALUES
  (1, 'WDG-001', 5, 'Best widget ever!', 'I have been using this widget daily for 3 months and it has never let me down. The build quality is excellent and the QuickLock mechanism is a joy to use. Highly recommend to anyone looking for a reliable everyday widget.', true, 42),
  (2, 'WDG-001', 4, 'Great value', 'Good widget for the price. Does everything it promises. Only giving 4 stars because I wish it came in more colors.', true, 18),
  (3, 'WDG-001', 5, 'Third one I have bought', 'Keep buying these as gifts for friends and family. Everyone loves them. The aluminum construction feels premium and the warranty is generous.', true, 31),
  (5, 'WDG-002', 5, 'Worth every penny', 'The Premium Widget is in a different league. The titanium body is gorgeous and the Bluetooth diagnostics are incredibly useful. I use the LifeGuard protection daily. This is the widget for serious users.', true, 67),
  (7, 'WDG-002', 5, 'Premium quality', 'Upgraded from the Standard and the difference is night and day. The adaptive resonance dampening alone is worth the price increase. The rose-gold finish is stunning.', true, 29),
  (11, 'WDG-002', 4, 'Almost perfect', 'Fantastic widget but the app could use some polish. The hardware itself is flawless. Battery life with Bluetooth active is shorter than I expected.', true, 15),
  (8, 'WDG-003', 4, 'Perfect for travel', 'I take this everywhere. It fits in my jacket pocket and weighs almost nothing. Performance is surprisingly close to the full-size Standard model.', true, 23),
  (14, 'WDG-003', 5, 'Great little widget', 'Do not let the size fool you. This Mini Widget punches way above its weight. Perfect for quick jobs and field work.', true, 12),
  (9, 'WDG-003', 3, 'Good but basic', 'It works fine for basic tasks but I found myself wanting the features of the Standard model. If you only do simple work, this is fine.', true, 8),
  (19, 'WDG-004', 5, 'Game changer for pros', 'The OLED display showing real-time parameters has transformed my workflow. I can now see exactly what is happening without connecting to a computer. The ruggedized housing survived a drop from my workbench — no damage at all.', true, 45),
  (25, 'WDG-004', 4, 'Excellent upgrade', 'Coming from the Standard Widget, the Pro X feels like jumping two generations ahead. The USB-C charging is fast and the display is crisp.', true, 19),
  (14, 'WDG-005', 4, 'Honest budget option', 'Does not pretend to be something it is not. For basic everyday tasks, this is all you need. Love the eco-friendly packaging too.', true, 11),
  (26, 'WDG-005', 3, 'You get what you pay for', 'It works but feels cheap compared to the Standard. Fine for occasional use but I would not rely on it for daily work.', false, 7),
  (15, 'WDG-006', 5, 'Built like a tank', 'We deployed six of these on our rig and they have been running flawlessly in extreme conditions for 4 months. Temperature swings from -20 to +50C and constant vibration — no issues whatsoever.', true, 89),
  (44, 'WDG-006', 5, 'Industrial grade means industrial grade', 'This is not marketing fluff. We tested it at -30C and it worked perfectly. The IP68 rating is legit — we submerged it accidentally and it was fine.', true, 54),
  (1, 'GDG-001', 4, 'Great starter gadget', 'Perfect for getting into the Gadget ecosystem. Simple to set up and the auto-calibration works well. I am already eyeing the Pro model for more advanced work.', true, 16),
  (4, 'GDG-001', 3, 'Decent but limited', 'Good for beginners but I outgrew it quickly. If you think you might need more power, just go for the Pro from the start.', true, 21),
  (13, 'GDG-001', 5, 'Perfect classroom gadget', 'We bought 30 for our STEM lab and the students love them. The simple one-button operation means less time troubleshooting and more time learning.', true, 38),
  (5, 'GDG-002', 4, 'Excellent for professional use', 'The dual-core processing makes a huge difference for batch operations. The Python SDK is well documented and I had custom scripts running within an hour.', true, 33),
  (19, 'GDG-002', 5, 'The workhorse', 'This is the tool I reach for every single day. Reliable, fast, and the 64GB storage means I never have to worry about running out of space for data logs.', true, 47),
  (7, 'GDG-002', 5, 'Worth the investment', 'Paid for itself within the first month. The BLE connectivity and the Node.js SDK let me build automated monitoring dashboards easily.', true, 28),
  (37, 'GDG-003', 5, 'Nothing else comes close', 'The Mega Gadget is in a class of its own. The 7-inch display is gorgeous, the quad-core processing handles anything I throw at it, and the hot-swappable modules are genius.', true, 71),
  (12, 'GDG-003', 5, 'Flagship for a reason', 'Every feature is best-in-class. The thermal management system lets it run at full power indefinitely without throttling.', true, 56),
  (11, 'GDG-003', 4, 'Amazing but heavy', 'Performance and features are incredible. My only complaint is the weight — at 800g, it is a lot to carry around all day. Worth it for the capability though.', true, 22),
  (24, 'GDG-004', 5, 'Surprisingly capable for its size', 'I was skeptical but the Nano is genuinely useful. I keep it on my keychain and use it for quick spot checks multiple times a day. Battery lasts about a week with daily use.', true, 19),
  (30, 'GDG-004', 4, 'Nice gadget to have', 'Not a replacement for a full-size gadget but great for when you just need a quick measurement. The clip design is clever.', true, 9),
  (22, 'GDG-005', 5, 'Creative dream tool', 'The pressure-sensitive touchscreen is incredibly responsive. Coming from a Wacom tablet, this feels more natural. The Figma integration is seamless.', true, 41),
  (37, 'GDG-005', 5, 'Best purchase of the year', 'The Studio has completely changed my workflow. 512GB is plenty for even my largest projects. The stylus precision is remarkable.', true, 36),
  (1, 'ACC-001', 5, 'Essential accessory', 'If you have both widgets and gadgets, you need this adapter. Works flawlessly with all my devices. The automatic protocol negotiation is seamless.', true, 25),
  (2, 'ACC-001', 4, 'Works as advertised', 'Simple, reliable adapter. Nothing fancy but it does exactly what it should.', true, 8),
  (7, 'ACC-002', 4, 'Good protection', 'The hard-shell case fits my Pro Gadget perfectly. The mesh pocket is handy for cables. The splash-proof zipper gives me confidence carrying it in the rain.', true, 14),
  (13, 'ACC-002', 5, 'Saved my gadget', 'Dropped my bag down a flight of stairs. Gadget was perfectly fine in this case. The EVA foam is thick and well-molded.', true, 33),
  (5, 'ACC-003', 5, 'Best charger I own', 'The GaN technology means this 65W charger is smaller than most 30W chargers. Charges everything fast. I travel with this exclusively now.', true, 29),
  (19, 'ACC-003', 5, 'Universal and compact', 'Works with 100-240V so I use it everywhere I travel. Folds flat in my bag. The dual-port setup charges my gadget and phone simultaneously.', true, 17),
  (19, 'ACC-004', 5, 'Lab essential', 'NIST-traceable calibration at this price point is a steal. The alignment jig makes the process quick and repeatable. Calibration certificate was accepted by our quality department without question.', true, 42),
  (5, 'ACC-005', 4, 'Elegant and functional', 'Beautiful stand that keeps my widget charged. The viewing angle is perfect for my desk setup. Wish it charged a bit faster than 15W.', true, 11),
  (1, 'ACC-006', 5, 'Cables that last', 'I have destroyed countless cheap cables but these braided ones are indestructible. The strain relief at the connectors is excellent. Having 3 lengths in one set is great.', true, 20),
  (8, 'ACC-007', 4, 'Handy travel organizer', 'Keeps all my cables and adapters neatly organized. The elastic loops hold everything in place even when the pouch is stuffed full.', true, 7),
  (22, 'ACC-008', 3, 'Does the job', 'Screen protectors are screen protectors. These are fine — no bubbles, decent oleophobic coating. Nothing special but they protect the display.', true, 5),
  (29, 'BDL-001', 5, 'Best value starter kit', 'Getting the widget, adapter, and case together at 15% off is a no-brainer. Everything works together perfectly out of the box.', true, 34),
  (5, 'BDL-002', 5, 'Everything a pro needs', 'Saved 20% by getting the bundle instead of buying pieces individually. The calibration kit alone justifies the Pro Gadget. Could not be happier with this purchase.', true, 28),
  (11, 'BDL-003', 5, 'The ultimate setup', 'Yes, it is expensive. But you get the Mega Gadget AND the Studio together. The 25% discount means you are basically getting the accessories for free. If you are serious about this, there is no better way to buy.', true, 63),
  (23, 'WDG-007', 5, 'A work of art', 'The walnut and brass finish is absolutely gorgeous. Each unit really is unique — the wood grain on mine is beautiful. It is also a great performer, not just a looker.', true, 38),
  (32, 'WDG-007', 5, 'Perfect gift', 'Bought this for my partner and they were blown away by the craftsmanship. The hand-finishing is evident in every detail.', false, 15),
  (24, 'GDG-006', 5, 'Trail tested and approved', 'Took this on a 10-day backpacking trip. Solar panel kept it charged, GPS was accurate, and it survived rain, dust, and a tumble into a creek. Cannot recommend enough for outdoor use.', true, 52),
  (29, 'GDG-006', 4, 'Great outdoor companion', 'IP67 rating is legit — used it in heavy rain with no issues. The GPS accuracy is within 3 meters. Only minor complaint is the solar charging is slow in overcast conditions.', true, 18),
  (37, 'ACC-009', 4, 'Convenient charging', 'The Qi2 magnetic alignment means I just set my gadget down and it starts charging — no fiddling with placement. 15W is fast enough for overnight charging.', true, 10),
  (15, 'ACC-010', 5, 'Rock solid mount', 'VESA compatible and incredibly sturdy. The tilt and swivel adjustments are smooth and stay where you set them. Supports my Mega Gadget with zero wobble.', true, 16),
  (9, 'WDG-008', 5, 'Impossibly small', 'I cannot believe how tiny this is. And it actually works well! Perfect for carrying as a backup in my EDC pouch.', true, 21),
  (40, 'WDG-008', 4, 'Cute and functional', 'The Micro is adorable and surprisingly useful. The stainless steel construction feels premium despite the tiny size.', true, 6),
  (13, 'GDG-007', 5, 'Transformed our STEM program', 'The curriculum-aligned lesson plans saved us weeks of prep time. Students love the Blockly programming interface. The sensor suite covers all the experiments in our syllabus.', true, 44),
  (44, 'GDG-007', 5, 'Best educational gadget', 'We replaced 5 separate tools with the Edu gadget. The Python support means advanced students can graduate from Blockly when they are ready. Brilliant product.', true, 31),
  (19, 'ACC-011', 5, 'Lab necessity', 'Should be mandatory in any electronics workspace. Good size, stays flat, and the ground cord reaches easily to any outlet. Proper ESD protection at a fair price.', true, 13),
  (37, 'ACC-012', 5, 'Stunning optics', 'The magnetic mount is genius — swap lenses in seconds with a satisfying click. The macro lens reveals incredible detail. The fisheye is fun for creative shots.', true, 27),
  (22, 'ACC-012', 4, 'Great lens variety', 'Four lenses cover most use cases. The glass quality is excellent — sharp corner to corner. Wish there was a super-telephoto option.', true, 14),
  (6, 'WDG-001', 4, 'Solid choice', 'Reliable performer. I use it alongside my Premium Widget for lighter tasks. The aluminum body holds up well over time.', true, 9),
  (10, 'GDG-004', 4, 'Handy keychain gadget', 'Perfect for quick checks when I do not want to dig out my full-size gadget.', true, 5),
  (16, 'GDG-002', 5, 'Team favorite', 'We have four of these in our lab and they are the most-used tools on the bench. The Node.js SDK makes automation straightforward.', true, 22),
  (35, 'ACC-003', 5, 'Travel essential', 'This is the only charger I pack now. Works in every country, charges everything. The foldable prongs are a nice touch.', true, 13),
  (46, 'WDG-005', 4, 'Decent entry point', 'Good enough for basic tasks and the price is right. The eco packaging is a plus.', true, 4);
