INSERT INTO notifications (user_id, channel, subject, body, metadata, status, sent_at, read_at) VALUES
  (1, 'email', 'Welcome to our store!', 'Hi Alice, welcome! Use code WELCOME10 for 10% off your first order.', '{"template": "welcome", "coupon": "WELCOME10"}', 'sent', '2026-01-01 10:00:00', '2026-01-01 10:15:00'),
  (1, 'email', 'Order Confirmed: #1', 'Your order #1 has been confirmed. Total: $38.47. We will notify you when it ships.', '{"template": "order_confirmed", "order_id": 1}', 'sent', '2026-01-15 10:31:00', '2026-01-15 10:45:00'),
  (1, 'email', 'Your order has shipped!', 'Order #1 is on its way! Tracking: FX-111222333 via FedEx.', '{"template": "order_shipped", "order_id": 1, "carrier": "FedEx", "tracking": "FX-111222333"}', 'sent', '2026-01-16 08:01:00', '2026-01-16 09:00:00'),
  (1, 'sms', 'Order delivered', 'Your order #1 has been delivered! Rate your purchase at shop.example.com/review', '{"template": "order_delivered", "order_id": 1}', 'sent', '2026-01-19 14:23:00', NULL),
  (2, 'email', 'Welcome to our store!', 'Hi Bob, welcome aboard!', '{"template": "welcome"}', 'sent', '2026-02-01 09:00:00', '2026-02-01 12:00:00'),
  (2, 'email', 'Order Confirmed: #3', 'Your order #3 has been confirmed.', '{"template": "order_confirmed", "order_id": 3}', 'sent', '2026-03-05 09:01:00', '2026-03-05 10:00:00'),
  (3, 'email', 'Welcome to our store!', 'Hi Carol, welcome!', '{"template": "welcome"}', 'sent', '2026-01-15 08:00:00', NULL),
  (4, 'email', 'Order Cancelled: #5', 'Your order #5 has been cancelled. Refund of $21.98 will be processed within 3-5 business days.', '{"template": "order_cancelled", "order_id": 5, "refund_amount": 2198}', 'sent', '2026-03-20 11:01:00', '2026-03-20 11:30:00'),
  (5, 'email', 'Congratulations! You reached Platinum!', 'Hi Eve, you have been upgraded to Platinum tier. Enjoy exclusive benefits and early access to new products.', '{"template": "tier_upgrade", "new_tier": "platinum"}', 'sent', '2026-03-01 08:00:00', '2026-03-01 09:15:00'),
  (5, 'push', 'Platinum tier unlocked!', 'You are now a Platinum member. Check your new benefits!', '{"template": "tier_upgrade_push"}', 'sent', '2026-03-01 08:00:00', '2026-03-01 08:05:00'),
  (11, 'email', 'Order Confirmed: #12', 'Your corporate order #12 has been confirmed. PO: PO-2026-0042.', '{"template": "order_confirmed", "order_id": 12, "corporate": true}', 'sent', '2026-01-20 09:01:00', '2026-01-20 09:30:00'),
  (12, 'email', 'Order Confirmed: #13', 'Your order #13 has been confirmed.', '{"template": "order_confirmed", "order_id": 13}', 'sent', '2026-02-05 12:01:00', '2026-02-05 14:00:00'),
  (1, 'email', 'Leave a review?', 'Hi Alice, how are you enjoying your Standard Widget? Leave a review and help other customers.', '{"template": "review_request", "sku": "WDG-001"}', 'sent', '2026-01-26 10:00:00', '2026-01-26 18:00:00'),
  (19, 'email', 'Order Confirmed: #19', 'Your lab order has been confirmed. 2x Pro Gadgets and calibration kit.', '{"template": "order_confirmed", "order_id": 19}', 'sent', '2026-02-20 08:01:00', '2026-02-20 08:30:00'),
  (37, 'email', 'Welcome to our store!', 'Hi Isla, welcome! You were referred by a friend — enjoy 15% off your first order.', '{"template": "welcome_referral", "referred_by": "user_29", "coupon": "REF15"}', 'sent', '2026-03-25 10:00:00', '2026-03-25 10:20:00'),
  (21, 'email', 'Weekly admin digest', 'Orders: 147 this week (+12% vs last week). Revenue: $89,234. Top seller: WDG-001 (43 units).', '{"template": "admin_digest", "period": "2026-W12"}', 'sent', '2026-03-23 06:00:00', '2026-03-23 08:00:00'),
  (44, 'email', 'Corporate account activated', 'Hi Paul, your corporate account has been approved. SSO login is now available.', '{"template": "corporate_activated"}', 'sent', '2026-05-15 09:00:00', '2026-05-15 09:10:00'),
  (1, 'email', 'Summer Sale: 15% off everything!', 'Hi Alice, our biggest sale of the year is here. Use SUMMER15 at checkout.', '{"template": "promo_blast", "coupon": "SUMMER15", "campaign": "summer-2026"}', 'sent', '2026-06-01 06:00:00', '2026-06-01 07:30:00'),
  (5, 'email', 'Summer Sale: 15% off everything!', 'Hi Eve, as a Platinum member you get early access. Use SUMMER15 at checkout.', '{"template": "promo_blast_vip", "coupon": "SUMMER15", "campaign": "summer-2026"}', 'sent', '2026-05-31 18:00:00', '2026-05-31 18:10:00'),
  (12, 'push', 'Price drop alert!', 'Gadget Studio is now 10% off for a limited time.', '{"template": "price_alert", "sku": "GDG-005"}', 'sent', '2026-06-10 12:00:00', '2026-06-10 12:05:00'),
  (7, 'email', 'Your order has shipped!', 'Order #8 is on its way! Tracking: via FedEx.', '{"template": "order_shipped", "order_id": 8}', 'sent', '2026-05-01 16:01:00', NULL),
  (25, 'email', 'Order Confirmed: #20', 'Your order has been confirmed.', '{"template": "order_confirmed", "order_id": 20}', 'sent', '2026-05-25 15:01:00', '2026-05-25 16:00:00'),
  (42, 'email', 'Payment pending', 'Your order #30 is awaiting payment confirmation.', '{"template": "payment_pending", "order_id": 30}', 'pending', NULL, NULL),
  (50, 'email', 'Order Confirmed: #36', 'Your order has been confirmed.', '{"template": "order_confirmed", "order_id": 36}', 'pending', NULL, NULL),
  (3, 'email', 'We miss you!', 'Hi Carol, it has been a while since your last visit. Here is 20% off your next order with code COMEBACK20.', '{"template": "win_back", "coupon": "COMEBACK20"}', 'sent', '2026-06-15 10:00:00', NULL);
